function solve(n: number): boolean {
    let sum = 0;
    let product = 1;
    let num = n;
    let digits: number[] = [];

    // Extract each digit and compute sum and product
    while (num > 0) {
        const digit = num % 10;
        digits.push(digit);
        sum += digit;
        product *= digit;
        num = Math.floor(num / 10);
    }

    // Handle the case where n is a single-digit number (product would be the digit itself)
    if (digits.length === 1) {
        product = digits[0];
    }

    const total = sum + product;

    // Check if n is divisible by the total (avoid division by zero)
    return total !== 0 && n % total === 0;
}
